1	/**
2	 * The Spider — public types.
3	 *
4	 * Rig and engine data model, CrawlResult, SpiderApi, and configuration.
5	 * Engine yield shapes (DraftYields, SealYields) live here too so downstream
6	 * packages can import them without depending on the engine implementation files.
7	 */
8	
9	import type { ZodSchema } from 'zod';
10	
11	// ── Engine instance status ────────────────────────────────────────────
12	
13	export type EngineStatus = 'pending' | 'running' | 'completed' | 'failed' | 'cancelled' | 'blocked';
14	
15	// ── Block record ──────────────────────────────────────────────────────
16	
17	/**
18	 * Persisted record of an active engine block.
19	 * Present on an EngineInstance when status === 'blocked'.
20	 * Cleared when the block is resolved.
21	 */
22	export interface BlockRecord {
23	  /** Block type identifier (matches a registered BlockType.id). */
24	  type: string;
25	  /** Structured condition payload — shape validated by the block type's conditionSchema. */
26	  condition: unknown;
27	  /** ISO timestamp when the engine was blocked. */
28	  blockedAt: string;
29	  /** Optional human-readable message from the engine. */
30	  message?: string;
31	  /** ISO timestamp of the last checker evaluation. Updated on every check cycle. */
32	  lastCheckedAt?: string;
33	}
34	
35	// ── Engine instance ───────────────────────────────────────────────────
36	
37	/**
38	 * A single engine slot within a rig.
39	 *
40	 * `id` is the engine's position identifier (e.g. 'draft', 'implement').
41	 * For the static pipeline it matches `designId`.
42	 *
43	 * `givensSpec` holds values set at spawn time (writ, role, commands) and
44	 * may contain unresolved yield reference strings ('$yields.<id>.<prop>')
45	 * that the Spider resolves at run time from upstream engine yields.
46	 */
47	export interface EngineInstance {
48	  /** Unique identifier within the rig (e.g. 'draft', 'implement'). */
49	  id: string;
50	  /** The engine design to look up in the Fabricator. */
51	  designId: string;
52	  /** Current execution status. */
53	  status: EngineStatus;
54	  /** Engine IDs that must be completed before this engine can run. */
55	  upstream: string[];
56	  /**
57	   * Givens values. Spawn-time references ($writ, $vars.*) are resolved to
58	   * their values. Yield references ($yields.*.*) remain as strings and are
59	   * resolved at run time when the engine is executed.
60	   */
61	  givensSpec: Record<string, unknown>;
62	  /** Yields from a completed engine run (JSON-serializable). */
63	  yields?: unknown;
64	  /** Error message if this engine failed. */
65	  error?: string;
66	  /** Session ID from a launched quick engine, used by the collect step. */
67	  sessionId?: string;
68	  /** ISO timestamp when execution started. */
69	  startedAt?: string;
70	  /** ISO timestamp when execution completed (or failed). */
71	  completedAt?: string;
72	  /** Present when status === 'blocked'. Cleared when the block is resolved. */
73	  block?: BlockRecord;
74	}
75	
76	// ── Rig ──────────────────────────────────────────────────────────────
77	
78	export type RigStatus = 'running' | 'completed' | 'failed' | 'blocked';
79	
80	/**
81	 * A rig — the execution context for a single writ.
82	 *
83	 * Stored in The Stacks (`spider/rigs` book). The `engines` array is the
84	 * ordered pipeline of engine instances. The Spider updates this document
85	 * in-place as engines run and complete.
86	 */
87	export interface RigDoc {
88	  /** Index signature required to satisfy BookEntry constraint. */
89	  [key: string]: unknown;
90	  /** Unique rig id. */
91	  id: string;
92	  /** The writ this rig is executing. */
93	  writId: string;
94	  /** Current rig status. */
95	  status: RigStatus;
96	  /** Ordered engine pipeline. */
97	  engines: EngineInstance[];
98	  /** ISO timestamp when the rig was created. */
99	  createdAt: string;
100	  /** Engine id whose yields provide the resolution summary. Set at spawn time. */
101	  resolutionEngineId?: string;
102	}
103	
104	// ── Rig filters ───────────────────────────────────────────────────────
105	
106	/**
107	 * Filters for listing rigs.
108	 */
109	export interface RigFilters {
110	  /** Filter by rig status. */
111	  status?: RigStatus;
112	  /** Maximum number of results (default: 20). */
113	  limit?: number;
114	  /** Number of results to skip. */
115	  offset?: number;
116	}
117	
118	// ── Rig templates ─────────────────────────────────────────────────────
119	
120	/**
121	 * A single engine slot declared in a rig template.
122	 */
123	export interface RigTemplateEngine {
124	  /** Engine id unique within this template. */
125	  id: string;
126	  /** Engine design id to look up in the Fabricator. */
127	  designId: string;
128	  /** Engine ids within this template whose completion is required first. Defaults to []. */
129	  upstream?: string[];
130	  /**
131	   * Givens to pass to the engine.
132	   * String values starting with '$' (either $name or ${name}) are variable
133	   * references:
134	   *   '$writ' or '${writ}' — the WritDoc for this rig's writ
135	   *   '$vars.<key>' or '${vars.<key>}' — value from spider.variables config
136	   *   '$yields.<engine_id>.<property>' or '${yields.<engine_id>.<property>}'
137	   *       — a property from an upstream engine's yields (resolved at run time)
138	   * Non-string values are passed through literally.
139	   * Variables that resolve to undefined cause the key to be omitted.
140	   */
141	  givens?: Record<string, unknown>;
142	}
143	
144	/**
145	 * A complete rig template.
146	 */
147	export interface RigTemplate {
148	  /** Ordered list of engine slot declarations. */
149	  engines: RigTemplateEngine[];
150	  /**
151	   * Engine id whose yields provide the writ resolution summary.
152	   * Falls back to seal engine, then last completed engine in array order.
153	   */
154	  resolutionEngine?: string;
155	}
156	
157	// ── CrawlResult ────────────────────────────────────────────────────────
158	
159	/**
160	 * The result of a single crawl() call.
161	 *
162	 * Variants, ordered by priority:
163	 * - 'engine-completed'  — an engine finished (collected or ran inline); rig still running
164	 * - 'engine-started'    — launched a quick engine's session
165	 * - 'engine-blocked'    — engine entered blocked status; rig is still running (other engines active)
166	 * - 'engine-unblocked'  — a blocked engine's condition cleared; engine returned to pending
167	 * - 'rig-spawned'       — created a new rig for a ready writ
168	 * - 'rig-completed'     — the crawl step caused a rig to reach a terminal state
169	 * - 'rig-blocked'       — all forward progress stalled; rig entered blocked status
170	 *
171	 * null means no work was available.
172	 */
173	export type CrawlResult =
174	  | { action: 'engine-completed'; rigId: string; engineId: string }
175	  | { action: 'engine-started'; rigId: string; engineId: string }
176	  | { action: 'engine-blocked'; rigId: string; engineId: string; blockType: string }
177	  | { action: 'engine-unblocked'; rigId: string; engineId: string }
178	  | { action: 'rig-spawned'; rigId: string; writId: string }
179	  | { action: 'rig-completed'; rigId: string; writId: string; outcome: 'completed' | 'failed' }
180	  | { action: 'rig-blocked'; rigId: string; writId: string };
181	
182	// ── Block type ────────────────────────────────────────────────────────
183	
184	/**
185	 * Result of a block type check.
186	 *
187	 * 'cleared' — condition met, unblock the engine.
188	 * 'pending' — condition not yet met, keep polling.
189	 * 'failed'  — condition is permanently unresolvable, fail the engine.
190	 *
191	 * When status is 'failed', an optional reason provides a human-readable
192	 * explanation that the Spider includes in the engine error message.
193	 */
194	export interface CheckResult {
195	  status: 'cleared' | 'pending' | 'failed';
196	  reason?: string;
197	}
198	
199	/** Summary info for a registered block type. */
200	export interface BlockTypeInfo {
201	  /** Block type id. */
202	  id: string;
203	  /** Plugin id that contributed this block type. */
204	  pluginId: string;
205	  /** Suggested poll interval in milliseconds, if set. */
206	  pollIntervalMs?: number;
207	}
208	
209	/** Summary info for a registered rig template. */
210	export interface RigTemplateInfo {
211	  /** Template name (plain for config, qualified pluginId.name for kit). */
212	  name: string;
213	  /** 'config' for guild.json templates, or the pluginId for kit-contributed templates. */
214	  source: string;
215	  /** The template definition. */
216	  template: RigTemplate;
217	}
218	
219	/**
220	 * A registered block type — defines how to check whether a blocking
221	 * condition has cleared. Contributed via kit/supportKit `blockTypes`.
222	 */
223	export interface BlockType {
224	  /** Unique identifier (e.g. 'writ-status', 'scheduled-time'). */
225	  id: string;
226	  /**
227	   * Check whether the blocking condition has been resolved.
228	   *
229	   * Return { status: 'cleared' } when the condition is met.
230	   * Return { status: 'pending' } when the condition is not yet met.
231	   * Return { status: 'failed' } or { status: 'failed', reason: '...' }
232	   * when the condition is permanently unresolvable.
233	   *
234	   * Throwing is reserved for transient errors (network failures, etc.)
235	   * — the engine stays blocked and the checker is retried next cycle.
236	   */
237	  check: (condition: unknown) => Promise<CheckResult>;
238	  /** Zod schema for validating the condition payload at block time. */
239	  conditionSchema: ZodSchema;
240	  /** Suggested poll interval in milliseconds. If absent, check every crawl cycle. */
241	  pollIntervalMs?: number;
242	}
243	
244	// ── SpiderApi ─────────────────────────────────────────────────────────
245	
246	/**
247	 * The Spider's public API — retrieved via guild().apparatus<SpiderApi>('spider').
248	 */
249	export interface SpiderApi {
250	  /**
251	   * Execute one step of the crawl loop.
252	   *
253	   * Priority ordering: collect > checkBlocked > run > spawn.
254	   * Returns null when no work is available.
255	   */
256	  crawl(): Promise<CrawlResult | null>;
257	
258	  /**
259	   * Show a rig by id. Throws if not found.
260	   */
261	  show(id: string): Promise<RigDoc>;
262	
263	  /**
264	   * List rigs with optional filters, ordered by createdAt descending.
265	   */
266	  list(filters?: RigFilters): Promise<RigDoc[]>;
267	
268	  /**
269	   * Find the rig for a given writ. Returns null if no rig exists.
270	   */
271	  forWrit(writId: string): Promise<RigDoc | null>;
272	
273	  /**
274	   * Manually clear a block on a specific engine, regardless of checker result.
275	   * Throws if the engine is not blocked.
276	   */
277	  resume(rigId: string, engineId: string): Promise<void>;
278	
279	  /**
280	   * Look up a registered block type by ID.
281	   */
282	  getBlockType(id: string): BlockType | undefined;
283	
284	  /**
285	   * List all registered block types with summary info.
286	   */
287	  listBlockTypes(): BlockTypeInfo[];
288	
289	  /**
290	   * List all registered rig templates with provenance info.
291	   */
292	  listTemplates(): RigTemplateInfo[];
293	
294	  /**
295	   * Return the merged effective writ-type → template-name mapping.
296	   * Config mappings override kit mappings for the same writ type.
297	   */
298	  listTemplateMappings(): Record<string, string>;
299	}
300	
301	// ── Configuration ─────────────────────────────────────────────────────
302	
303	/**
304	 * Spider apparatus configuration — lives under the `spider` key in guild.json.
305	 */
306	export interface SpiderConfig {
307	  /**
308	   * Polling interval for crawlContinual tool (milliseconds).
309	   * Default: 5000.
310	   */
311	  pollIntervalMs?: number;
312	  /**
313	   * Build command to pass to quick engines.
314	   */
315	  buildCommand?: string;
316	  /**
317	   * Test command to pass to quick engines.
318	   */
319	  testCommand?: string;
320	  /**
321	   * Named rig templates. Keys are template names (not writ types).
322	   * Templates are looked up by name via rigTemplateMappings.
323	   * A template named 'default' is used as the fallback when no mapping matches.
324	   */
325	  rigTemplates?: Record<string, RigTemplate>;
326	  /**
327	   * Writ type → rig template name mappings.
328	   * 'default' key is the fallback for unmatched writ types.
329	   * Config mappings override kit-contributed mappings for the same writ type.
330	   */
331	  rigTemplateMappings?: Record<string, string>;
332	  /**
333	   * User-defined variables available in rig template givens via '$vars.<key>'.
334	   * Values are passed through literally (string, number, boolean).
335	   * Variables resolving to undefined (key absent) cause the givens key to be omitted.
336	   */
337	  variables?: Record<string, unknown>;
338	}
339	
340	// ── Engine yield shapes ───────────────────────────────────────────────
341	
342	/**
343	 * Yields from the `draft` clockwork engine.
344	 * The Spider stores these in the engine instance and passes them
345	 * to downstream engines via context.upstream['draft'].
346	 */
347	export interface DraftYields {
348	  /** The draft's unique id. */
349	  draftId: string;
350	  /** Codex this draft belongs to. */
351	  codexName: string;
352	  /** Git branch name for the draft. */
353	  branch: string;
354	  /** Absolute filesystem path to the draft's worktree. */
355	  path: string;
356	  /** HEAD commit SHA at the time the draft was opened. Used by review engine to compute diffs. */
357	  baseSha: string;
358	}
359	
360	/**
361	 * Yields from the `seal` clockwork engine.
362	 */
363	export interface SealYields {
364	  /** The commit SHA at head of the target branch after sealing. */
365	  sealedCommit: string;
366	  /** Git strategy used. */
367	  strategy: 'fast-forward' | 'rebase';
368	  /** Number of retry attempts. */
369	  retries: number;
370	  /** Number of inscriptions (commits) sealed. */
371	  inscriptionsSealed: number;
372	}
373	
374	/**
375	 * Yields from the `implement` quick engine.
376	 * Set by the Spider's collect step when the Animator session completes.
377	 */
378	export interface ImplementYields {
379	  /** The Animator session id. */
380	  sessionId: string;
381	  /** Terminal status of the session. */
382	  sessionStatus: 'completed' | 'failed';
383	}
384	
385	/**
386	 * A single mechanical check (build or test) run by the review engine
387	 * before launching the reviewer session.
388	 */
389	export interface MechanicalCheck {
390	  /** Check name. */
391	  name: 'build' | 'test';
392	  /** Whether the command exited with code 0. */
393	  passed: boolean;
394	  /** Combined stdout+stderr, truncated to 4KB. */
395	  output: string;
396	  /** Wall-clock duration of the check in milliseconds. */
397	  durationMs: number;
398	}
399	
400	/**
401	 * Yields from the `review` quick engine.
402	 * Assembled by the Spider's collect step from session.output and session.metadata.
403	 */
404	export interface ReviewYields {
405	  /** The Animator session id. */
406	  sessionId: string;
407	  /** Reviewer's overall assessment — true if the review passed. */
408	  passed: boolean;
409	  /** Structured markdown findings from the reviewer's final message. */
410	  findings: string;
411	  /** Mechanical check results run before the reviewer session. */
412	  mechanicalChecks: MechanicalCheck[];
413	}
414	
415	/**
416	 * Yields from the `revise` quick engine.
417	 * Set by the Spider's collect step when the Animator session completes.
418	 */
419	export interface ReviseYields {
420	  /** The Animator session id. */
421	  sessionId: string;
422	  /** Terminal status of the session. */
423	  sessionStatus: 'completed' | 'failed';
424	}
425	
426	// ── Input request types ──────────────────────────────────────────────
427	
428	export type InputRequestStatus = 'pending' | 'completed' | 'rejected';
429	
430	export interface ChoiceQuestionSpec {
431	  type: 'choice';
432	  /** Human-readable question text. */
433	  label: string;
434	  /** Key → display label options map. */
435	  options: Record<string, string>;
436	  /** When true, the patron can supply a freeform answer instead of selecting. */
437	  allowCustom: boolean;
438	}
439	
440	export interface BooleanQuestionSpec {
441	  type: 'boolean';
442	  /** Human-readable question text. */
443	  label: string;
444	}
445	
446	export interface TextQuestionSpec {
447	  type: 'text';
448	  /** Human-readable question text. */
449	  label: string;
450	}
451	
452	export type QuestionSpec = ChoiceQuestionSpec | BooleanQuestionSpec | TextQuestionSpec;
453	
454	/** Discriminated choice answer — selected from options or freeform custom. */
455	export type ChoiceAnswer = { selected: string } | { custom: string };
456	
457	/**
458	 * Answer value union. Runtime type is determined by the corresponding QuestionSpec:
459	 * - choice → ChoiceAnswer (object with 'selected' or 'custom' key)
460	 * - boolean → boolean
461	 * - text → string
462	 */
463	export type AnswerValue = ChoiceAnswer | boolean | string;
464	
465	/**
466	 * An input request document stored in the spider/input-requests book.
467	 * Created by engines before blocking; answered by patrons via CLI tools.
468	 */
469	export interface InputRequestDoc {
470	  [key: string]: unknown;
471	  /** Unique ID via generateId('ir', 4). */
472	  id: string;
473	  /** Rig this request belongs to. */
474	  rigId: string;
475	  /** Engine that created this request. */
476	  engineId: string;
477	  /** Request lifecycle status. */
478	  status: InputRequestStatus;
479	  /** Optional human-readable context from the engine. */
480	  message?: string;
481	  /** Question key → question spec. */
482	  questions: Record<string, QuestionSpec>;
483	  /** Question key → answer value. Partially filled until completion. */
484	  answers: Record<string, AnswerValue>;
485	  /** Set when status transitions to 'rejected'. */
486	  rejectionReason?: string;
487	  /** ISO timestamp when the request was created. */
488	  createdAt: string;
489	  /** ISO timestamp of the last mutation. */
490	  updatedAt: string;
491	}
492	
493	// Augment GuildConfig so `guild().guildConfig().spider` is typed.
494	declare module '@shardworks/nexus-core' {
495	  interface GuildConfig {
496	    spider?: SpiderConfig;
497	  }
498	}
