      name: 'test-guild',
      nexus: '0.0.0',
      plugins: [],
      spider: { rigTemplates: { default: template }, variables: {} },
    };

    const fakeGuild: Guild = {
      home: '/tmp/test-guild',
      apparatus<T>(name: string): T {
